1	import { useState } from "react";
2	import { useParams } from "react-router-dom";
3	import { useMarket, useMarketEvents, useAccountRisk, useMarketPriceSubscription } from "@/lib/query/hooks";
4	import { useSession } from "@/features/session/context";
5	import { StatusBadge } from "@/components/ui/StatusBadge";
6	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
7	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
8	import { formatCurrency, timeUntil, truncateHash, formatRelativeTime } from "@/lib/utils/format";
9	import { AssumptionProvider } from "@/features/assumptions/AssumptionContext";
10	import { AssumptionPanel } from "@/features/assumptions/AssumptionPanel";
11	import { BayesNetGraph } from "@/features/graph/BayesNetGraph";
12	import { JunctionTreePanel } from "@/features/graph/JunctionTreePanel";
13	import { DiscussionThread } from "@/features/market/DiscussionThread";
14	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
15	import { EventTradePanel } from "@/features/trading/EventTradePanel";
16	import type { MarketEvent } from "@/lib/api/types";
17	
18	export default function MarketDetail() {
19	  const { marketId } = useParams<{ marketId: string }>();
20	  const { session, isConfigured } = useSession();
21	  const { data, isLoading, error } = useMarket(marketId!);
22	  const events = useMarketEvents(marketId!);
23	  const accountRisk = useAccountRisk(session.accountId);
24	  const isActiveMarket = data?.market.status === "active";
25	
26	  useMarketPriceSubscription(marketId ?? "", {
27	    enabled: Boolean(marketId) && !isLoading && !error && isActiveMarket,
28	  });
29	
30	  if (isLoading) return <LoadingPage />;
31	  if (error) return <ErrorMessage message={error instanceof Error ? error.message : "Market not found"} />;
32	  if (!data) return null;
33	
34	  const m = data.market;
35	
36	  return (
37	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
38	      <div>
39	        <div style={{ display: "flex", gap: "var(--space-md)", alignItems: "center", marginBottom: "var(--space-sm)" }}>
40	          <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>{m.title}</h1>
41	          <StatusBadge status={m.status} />
42	        </div>
43	        <p style={{ color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>{m.description}</p>
44	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.85rem", color: "var(--color-text-muted)" }}>
45	          <span>Volume: {formatCurrency(m.volume)}</span>
46	          <span>Liquidity: {formatCurrency(m.liquidity)}</span>
47	          <span>Expires: {timeUntil(m.expires_at)}</span>
48	        </div>
49	      </div>
50	
51	      <ProbabilityBar outcomes={m.outcomes} marginals={m.marginals} />
52	
53	      <PositionCard marketId={m.id} accountRisk={accountRisk.data} isConfigured={isConfigured} />
54	
55	      <ResolveMarketPanel market={m} />
56	
57	      {m.status === "active" && (
58	        <AssumptionProvider>
59	          <AssumptionPanel market={m} />
60	        </AssumptionProvider>
61	      )}
62	
63	      <EventTradePanel market={m} />
64	
65	      <DiscussionThread market={m} />
66	
67	      <BayesNetGraph focusMarketId={m.id} />
68	
69	      {/* Event Journal */}
70	      <div>
71	        <h2 style={{ fontSize: "1.1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>Event Journal</h2>
72	        {events.isLoading && <LoadingPage />}
73	        {events.data && events.data.events.length === 0 && (
74	          <span style={{ color: "var(--color-text-muted)", fontSize: "0.85rem" }}>No events yet.</span>
75	        )}
76	        {events.data && events.data.events.length > 0 && (
77	          <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
78	            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
79	              <thead>
80	                <tr style={{ background: "var(--color-bg-hover)" }}>
81	                  <th style={thStyle}>Seq</th>
82	                  <th style={thStyle}>Type</th>
83	                  <th style={thStyle}>Hash</th>
84	                  <th style={thStyle}>Time</th>
85	                </tr>
86	              </thead>
87	              <tbody>
88	                {events.data.events.map((e) => (
89	                  <EventRow key={e.eventId} event={e} />
90	                ))}
91	              </tbody>
92	            </table>
93	          </div>
94	        )}
95	      </div>
96	
97	      <JunctionTreePanel marketId={m.id} />
98	    </div>
99	  );
100	}
101	
102	function PositionCard({
103	  marketId,
104	  accountRisk,
105	  isConfigured,
106	}: {
107	  marketId: string;
108	  accountRisk: import("@/lib/api/types").AccountRiskResponse | undefined;
109	  isConfigured: boolean;
110	}) {
111	  if (!isConfigured || !accountRisk) return null;
112	
113	  const marketRisk = accountRisk.account.risk.minAssets.markets.find(
114	    (mr) => mr.marketId === marketId,
115	  );
116	
117	  if (!marketRisk) return null;
118	
119	  const utilColor = marketRisk.utilization > 0.8
120	    ? "var(--color-danger)"
121	    : marketRisk.utilization > 0.5
122	      ? "var(--color-warning, orange)"
123	      : "var(--color-text)";
124	
125	  return (
126	    <div style={positionCardStyle}>
127	      <div style={{ fontSize: "0.8rem", fontWeight: 600, marginBottom: "var(--space-xs)" }}>
128	        Your Position
129	      </div>
130	      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "var(--space-sm)", fontSize: "0.8rem" }}>
131	        <div>
132	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Min Asset</div>
133	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600 }}>{marketRisk.minAsset.toFixed(2)}</div>
134	        </div>
135	        <div>
136	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Utilization</div>
137	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600, color: utilColor }}>
138	            {(marketRisk.utilization * 100).toFixed(1)}%
139	          </div>
140	        </div>
141	        <div>
142	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Trades</div>
143	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600 }}>{marketRisk.commandCount}</div>
144	        </div>
145	      </div>
146	    </div>
147	  );
148	}
149	
150	function EventRow({ event }: { event: MarketEvent }) {
151	  const [expanded, setExpanded] = useState(false);
152	  const hasPayload = Object.keys(event.payload).length > 0;
153	
154	  return (
155	    <>
156	      <tr
157	        onClick={() => hasPayload && setExpanded(!expanded)}
158	        style={{ borderTop: "1px solid var(--color-border)", cursor: hasPayload ? "pointer" : "default" }}
159	      >
160	        <td style={tdStyle}>{event.seq}</td>
161	        <td style={tdStyle}>
162	          {hasPayload && <span style={{ marginRight: 4, fontSize: "0.65rem" }}>{expanded ? "\u25BC" : "\u25B6"}</span>}
163	          {event.type}
164	        </td>
