139	function joinUrlPath(basePath: string, path: string): string {
140	  const normalizedBase = basePath === "/" ? "" : basePath.replace(/\/$/, "");
141	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
142	  return `${normalizedBase}${normalizedPath}`;
143	}
