146	  const baseUrl = API_BASE
147	    ? new URL(API_BASE, window.location.origin)
148	    : new URL(window.location.origin);
149	  const socketUrl = new URL(baseUrl.toString());
150	  socketUrl.protocol = socketUrl.protocol === "https:" ? "wss:" : "ws:";
151	  socketUrl.pathname = joinUrlPath(
152	    socketUrl.pathname,
153	    `/ws/markets/${encodeURIComponent(marketId)}/prices`,
154	  );
155	  socketUrl.search = "";
156	  socketUrl.hash = "";
157	  return socketUrl.toString();
158	}
