49	function readPositionLimitDetails(error: BayesApiError): PositionLimitExceededDetails {
50	  return {
51	    requestedSize: readNumericDetail(error.details.requestedSize),
52	    currentNetSize: readNumericDetail(error.details.currentNetSize),
